16	    title: "ETH Price > $3000 on March 15",
17	    description: "Will ETH trade above $3000?",
18	    variableId: "eth_price_gt_3000_mar15",
19	    status: "active" as const,
20	    outcomes: [
21	      { id: "yes", name: "Yes" },
22	      { id: "no", name: "No" },
23	    ],
24	    marginals: { yes: 0.65, no: 0.35 },
25	    liquidity: 150000,
26	    volume: 45000,
27	    created_at: "2026-03-01T00:00:00Z",
28	    expires_at: "2026-12-31T23:59:59Z",
