1	import { useState } from "react";
2	import { useSession } from "@/features/session/context";
3	import { useMarketComments, usePostMarketComment } from "@/lib/query/hooks";
4	import { formatRelativeTime } from "@/lib/utils/format";
5	import type { Market } from "@/lib/api/types";
6	
7	const MAX_COMMENT_BODY_LENGTH = 2000;
8	
9	interface DiscussionThreadProps {
10	  market: Market;
11	}
12	
13	export function DiscussionThread({ market }: DiscussionThreadProps) {
14	  const { session, isConfigured } = useSession();
15	  const comments = useMarketComments(market.id);
16	  const mutation = usePostMarketComment(market.id);
17	  const [body, setBody] = useState("");
18	
19	  const trimmedBody = body.trim();
20	  const remaining = MAX_COMMENT_BODY_LENGTH - body.length;
21	  const isReadOnly = market.status !== "active";
22	
23	  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
24	    event.preventDefault();
25	    if (!isConfigured || isReadOnly || !trimmedBody) {
26	      return;
27	    }
28	
29	    mutation.mutate(
30	      {
31	        payload: {
32	          accountId: session.accountId,
33	          body: trimmedBody,
34	          idempotencyKey: crypto.randomUUID(),
35	        },
36	        session,
37	      },
38	      {
39	        onSuccess: () => {
40	          setBody("");
41	        },
42	      },
43	    );
44	  };
45	
46	  return (
47	    <section style={panelStyle}>
48	      <div style={headerStyle}>
49	        <div>
50	          <h2 style={titleStyle}>Discussion</h2>
51	          <p style={subtitleStyle}>Market commentary and participant notes.</p>
52	        </div>
53	        {comments.data && (
54	          <span style={countStyle}>
55	            {comments.data.pagination.returned} comment{comments.data.pagination.returned === 1 ? "" : "s"}
56	          </span>
57	        )}
58	      </div>
59	
60	      <div style={threadStyle}>
61	        {comments.isLoading && <span style={mutedTextStyle}>Loading discussion...</span>}
62	        {comments.isError && (
63	          <span style={errorTextStyle}>
64	            {comments.error instanceof Error ? comments.error.message : "Failed to load comments"}
65	          </span>
66	        )}
67	        {comments.data && comments.data.comments.length === 0 && (
68	          <span style={mutedTextStyle}>No comments yet.</span>
69	        )}
70	        {comments.data && comments.data.comments.length > 0 && (
71	          <div style={commentListStyle}>
72	            {comments.data.comments.map((comment) => (
73	              <article key={comment.commentId} style={commentCardStyle}>
74	                <div style={commentMetaRowStyle}>
75	                  <strong style={commentAuthorStyle}>{comment.accountId}</strong>
76	                  <span style={commentMetaStyle}>#{comment.seq}</span>
77	                  <span style={commentMetaStyle}>{formatRelativeTime(comment.createdAt)}</span>
78	                </div>
79	                <p style={commentBodyStyle}>{comment.body}</p>
80	              </article>
81	            ))}
82	          </div>
83	        )}
84	      </div>
85	
86	      {isReadOnly ? (
87	        <div style={noteStyle}>Discussion is read-only because this market is {market.status}.</div>
88	      ) : !isConfigured ? (
89	        <div style={noteStyle}>Set your Account ID in the header to join the discussion.</div>
90	      ) : (
91	        <form onSubmit={handleSubmit} style={composerStyle}>
92	          <label style={{ display: "grid", gap: "var(--space-xs)" }}>
93	            <span style={labelStyle}>Add a comment</span>
94	            <textarea
95	              value={body}
96	              onChange={(event) => setBody(event.target.value)}
97	              placeholder="Share your thesis, assumptions, or trade rationale."
98	              maxLength={MAX_COMMENT_BODY_LENGTH}
99	              rows={4}
100	              style={textareaStyle}
101	            />
102	          </label>
103	          <div style={composerFooterStyle}>
104	            <span style={mutedTextStyle}>{remaining} characters remaining</span>
105	            <button
106	              type="submit"
107	              disabled={!trimmedBody || mutation.isPending}
108	              style={{
109	                ...submitButtonStyle,
110	                opacity: !trimmedBody || mutation.isPending ? 0.6 : 1,
111	                cursor: !trimmedBody || mutation.isPending ? "not-allowed" : "pointer",
112	              }}
113	            >
114	              {mutation.isPending ? "Posting..." : "Post Comment"}
115	            </button>
116	          </div>
117	          {mutation.isError && (
118	            <div style={errorTextStyle}>
119	              {mutation.error instanceof Error ? mutation.error.message : "Failed to post comment"}
120	            </div>
121	          )}
122	        </form>
123	      )}
124	    </section>
125	  );
126	}
127	
128	const panelStyle: React.CSSProperties = {
129	  padding: "var(--space-md)",
130	  borderRadius: "var(--radius-md)",
131	  border: "1px solid var(--color-border)",
132	  background: "var(--color-bg-surface)",
133	  display: "grid",
134	  gap: "var(--space-md)",
135	};
136	
137	const headerStyle: React.CSSProperties = {
138	  display: "flex",
139	  alignItems: "center",
140	  justifyContent: "space-between",
141	  gap: "var(--space-md)",
142	  flexWrap: "wrap",
143	};
144	
145	const titleStyle: React.CSSProperties = {
146	  margin: 0,
147	  fontSize: "1.1rem",
