76	export function normalizeMarketListFilters(
77	  filters?: MarketListFilterInput,
78	): NormalizedMarketListFilters {
79	  const status = typeof filters === "string"
80	    ? filters
81	    : filters?.status;
82	  const includeResolved = (
83	    typeof filters !== "string"
84	    && filters?.includeResolved === true
85	  ) || status === "resolved";
86	
87	  return {
88	    ...(status ? { status } : {}),
89	    ...(includeResolved ? { includeResolved: true } : {}),
90	  };
91	}
92	
93	function serializeMarketListFilters(filters?: MarketListFilterInput): string {
94	  const normalizedFilters = normalizeMarketListFilters(filters);
95	  const params = new URLSearchParams();
96	
97	  if (normalizedFilters.status) {
98	    params.set("status", normalizedFilters.status);
99	  }
100	
101	  if (normalizedFilters.includeResolved) {
102	    params.set("include_resolved", "true");
103	  }
104	
105	  const queryString = params.toString();
106	  return queryString ? `?${queryString}` : "";
107	}
