  borderRadius: "var(--radius-sm)",
  border: "1px solid var(--color-border)",
  background: "var(--color-bg)",
  padding: "var(--space-sm) var(--space-md)",
  display: "grid",
  gap: "var(--space-xs)",
};

const commentMetaRowStyle: React.CSSProperties = {
  display: "flex",
  flexWrap: "wrap",
  alignItems: "center",
  gap: "var(--space-sm)",
};

const commentAuthorStyle: React.CSSProperties = {
  fontSize: "0.85rem",
  fontWeight: 600,
};

const commentMetaStyle: React.CSSProperties = {
  color: "var(--color-text-muted)",
  fontSize: "0.75rem",
};

const commentBodyStyle: React.CSSProperties = {
  margin: 0,
  whiteSpace: "pre-wrap",
  lineHeight: 1.5,
  fontSize: "0.9rem",
};

const composerStyle: React.CSSProperties = {
  display: "grid",
  gap: "var(--space-sm)",
  paddingTop: "var(--space-xs)",
  borderTop: "1px solid var(--color-border)",
};

const labelStyle: React.CSSProperties = {
  fontSize: "0.85rem",
  fontWeight: 600,
};

const textareaStyle: React.CSSProperties = {
  width: "100%",
  padding: "10px 12px",
  borderRadius: "var(--radius-sm)",
  border: "1px solid var(--color-border)",
  background: "var(--color-bg)",
  color: "var(--color-text)",
  fontSize: "0.9rem",
  fontFamily: "inherit",
  resize: "vertical",
};

const composerFooterStyle: React.CSSProperties = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  gap: "var(--space-sm)",
  flexWrap: "wrap",
};

const submitButtonStyle: React.CSSProperties = {
  padding: "8px 14px",
  borderRadius: "var(--radius-sm)",
  border: "none",
  background: "var(--color-primary)",
  color: "#fff",
  fontWeight: 600,
  fontSize: "0.85rem",
};

const noteStyle: React.CSSProperties = {
  padding: "var(--space-sm) var(--space-md)",
  borderRadius: "var(--radius-sm)",
  border: "1px dashed var(--color-border)",
  color: "var(--color-text-muted)",
  background: "rgba(15, 23, 42, 0.02)",
  fontSize: "0.85rem",
};

const mutedTextStyle: React.CSSProperties = {
  color: "var(--color-text-muted)",
